-- =============================================================================
-- Migration: 0189_cb_og_figures.sql
-- Wire 95 cropped figure images (graphs / geometry / charts) into the
-- CB OG #1–#10 questions seeded by 0164–0173. Images are served from
-- viewer/public/data/tests/cb-og-N/figures/mM-qN.png (committed to the repo,
-- deployed by Cloudflare Pages). Sets test_questions.figure + passage_alt (the
-- figure description, also the a11y alt text) and resets passage to the clean
-- original (the seed had folded the description into passage while there was no
-- image). Tables stay as text in passage (not touched here). Idempotent.
-- =============================================================================

UPDATE public.test_questions tq SET figure='/data/tests/cb-og-1/figures/m3-q11.png', passage_alt='Scatterplot in the first quadrant. The x-axis runs from 0 to 8 (gridlines at 1,2,3,4,5,6,7,8) and the y-axis runs from 0 to 10 (gridlines at 1 through 10). Plotted data points form a positive linear trend rising from lower-left to upper-right: points are located approximately at (1,0), (1.5,1), (2,2), (2.5,3), (3,4), (3.5,4), (4,6), (4.5,7), (5,7), (5.5,8), (6,9), (6.5,10). The points trend upward with positive slope.', passage=NULL
  FROM public.test_modules tm, public.tests t
  WHERE tq.module_id=tm.id AND tm.test_id=t.id AND t.slug='cb-og-1' AND tm.position=3 AND tq.number=11;
