UPDATE public.test_questions tq SET figure='/data/tests/cb-og-9/figures/m1-q13.png', passage_alt='Bar graph titled "Metal Content of Plants with and without Kanamycin Exposure." Y-axis: Metal content (parts per million), 0 to 700. X-axis: Experimental condition (without kanamycin, with kanamycin). Bars show iron and zinc levels for each condition (legend: zinc, iron).', passage='Many plants lose their leaf color when exposed to kanamycin, an antibiotic produced by some soil microorganisms. Spelman College biologist Mentewab Ayalew and her colleagues hypothesized that plants'' response to kanamycin exposure involves altering their uptake of metals, such as iron and zinc. The researchers grew two groups of seedlings of the plant Arabidopsis thaliana, half of which were exposed to kanamycin and half of which were a control group without exposure to kanamycin, and measured the plants'' metal content five days after germination.'
  FROM public.test_modules tm, public.tests t
  WHERE tq.module_id=tm.id AND tm.test_id=t.id AND t.slug='cb-og-9' AND tm.position=1 AND tq.number=13;
UPDATE public.test_questions tq SET figure='/data/tests/cb-og-9/figures/m1-q15.png', passage_alt='Bar graph titled "Percentage of Nonhexagonal Cells in Hives of Three Honeybee Species." Y-axis: Average percentage of nonhexagonal cells, 0 to 3.0. X-axis: Species (black dwarf honeybee, dwarf honeybee, western honeybee). Bars grouped by cell type (legend: 5-sided cells, 7-sided cells, 8-sided cells).', passage='Honeybee hives consist mainly of hexagonal (six-sided) units called cells, in which queens lay eggs. Hexagonal cells for eggs that develop into nonreproductive workers are smaller than those for eggs that develop into reproductive drones, though the size difference varies by species. Difference in cell size results in a construction problem—it''s hard to neatly connect sections of small cells to sections of large cells—that worsens as the difference increases. To fill in gaps between the sections when building a hive, bees rely on cells that have more or fewer than six sides. A student studying beehive structure consults data on three species, concluding that ______'
  FROM public.test_modules tm, public.tests t
  WHERE tq.module_id=tm.id AND tm.test_id=t.id AND t.slug='cb-og-9' AND tm.position=1 AND tq.number=15;
